    deity: { en: 'Lakshmi / Krishna', hi: 'लक्ष्मी / कृष्ण', sa: 'लक्ष्मीः / कृष्णः', ta: 'லக்ஷ்மி / கிருஷ்ணர்', te: 'లక్ష్మీ / కృష్ణుడు', bn: 'লক্ষ্মী / কৃষ্ণ', kn: 'ಲಕ್ಷ್ಮಿ / ಕೃಷ್ಣ', gu: 'લક્ષ્મી / કૃષ્ણ', mr: 'लक्ष्मी / कृष्ण', mai: 'लक्ष्मी / कृष्ण' },
