/* ═══════════════════════════════════════════
   HELPERS
   ═══════════════════════════════════════════ */

/** Map from sidereal Sun sign (1-12) at the STARTING New Moon to Amant month name.
 * Classical Vedic convention (Surya Siddhanta / Dharmasindhu):
 *   Mesha Sankranti (sign 1) governs Vaishakha
 *   Meena Sankranti (sign 12) governs Chaitra
 * Used with sign1 (Sun at starting NM). For Adhika months, sign1===sign2
 * and getHinduMonth(sign1) returns the correct name directly (e.g., Meena→Chaitra).
 * Verified: 2026 20/20 festivals, 2027 no false Adhika, 2029 Adhika Chaitra. */
const SOLAR_MONTH_MAP: Record<number, string> = {
  1: 'vaishakha', 2: 'jyeshtha', 3: 'ashadha', 4: 'shravana',
  5: 'bhadrapada', 6: 'ashwina', 7: 'kartika', 8: 'margashirsha',
  9: 'pausha', 10: 'magha', 11: 'phalguna', 12: 'chaitra',
};

/** Get the Hindu month name from a sign number (1-12, wraps for values >12) */
export function getHinduMonth(signNum: number): string {
  const wrapped = ((signNum - 1) % 12) + 1; // wrap 13→1, 14→2, etc.
  return SOLAR_MONTH_MAP[wrapped] || 'chaitra';
}

/** Ordered list of Hindu months for cycling */
const MONTH_ORDER = ['chaitra', 'vaishakha', 'jyeshtha', 'ashadha', 'shravana', 'bhadrapada', 'ashwina', 'kartika', 'margashirsha', 'pausha', 'magha', 'phalguna'];

/** Get the NEXT Hindu month name */
export function getNextHinduMonth(monthName: string): string {
  const idx = MONTH_ORDER.indexOf(monthName);
  if (idx === -1) return monthName;
  return MONTH_ORDER[(idx + 1) % 12];
}

/** Get the PREVIOUS Hindu month name */
export function getPreviousHinduMonth(monthName: string): string {
  const idx = MONTH_ORDER.indexOf(monthName);
  if (idx === -1) return monthName;
  return MONTH_ORDER[(idx + 11) % 12]; // +11 = -1 mod 12
}

/** Get the specific Ekadashi name for a given Hindu month and paksha */
export function getEkadashiName(hinduMonth: string, paksha: 'shukla' | 'krishna'): EkadashiDetail | undefined {
  return EKADASHI_NAMES[hinduMonth]?.[paksha];
}

/**
 * Canonical Ekadashi resolution — given a masa + paksha, returns the
 * `EkadashiDetail` (name, story, benefit) the consumer should display.
 *
 * Adhik Maas Ekadashis have dedicated names (Padmini for shukla,
 * Parama for krishna) — these are NOT the same as the regular Nirjala
 * / Apara / etc. for the masa they extend. Bug shipped: the /ekadashi
 * page looked up by masa.amanta alone, which returns "Jyeshtha" for
 * both Adhik Jyeshtha AND the regular Jyeshtha, so both Ekadashis were
 * labelled "Nirjala". The festival generator already handled this
 * correctly via its own internal resolveEkadashiName; this export
 * centralises the logic so both surfaces stay aligned (Lesson ZA).
 *
 * Returns undefined only when masa.amanta is empty AND not Adhika —
 * caller should fall back to a generic "Shukla/Krishna Ekadashi"
 * label if needed.
 */
export function resolveEkadashiDetail(
  masa: { amanta: string; isAdhika?: boolean } | undefined | null,
  paksha: 'shukla' | 'krishna',
): EkadashiDetail | undefined {
  // `masa` is optional on FestivalEntry — caller may pass undefined
  // from a feed that didn't fill in the masa block. Return undefined
  // and let the caller decide whether to fall back to a generic label.
  if (!masa) return undefined;
  if (masa.isAdhika) {
    return paksha === 'shukla' ? ADHIKA_MASA_EKADASHI.shukla : ADHIKA_MASA_EKADASHI.krishna;
  }
  return getEkadashiName(masa.amanta, paksha);
}

